    //
      (function() {
        // 1. 화면을 그리기 전에 애니메이션부터 강제로 끕니다.
        document.body.classList.add('preload-theme');

        // 2. 테마를 확인하고 즉시 라이트 모드 옷을 입힙니다.
        var mode = localStorage.getItem('blog-theme-mode');
        if (mode === 'light') {
          document.body.classList.add('light-mode');
        } else if (mode === 'auto') {
          if (window.matchMedia('(prefers-color-scheme: light)').matches) {
            document.body.classList.add('light-mode');
          }
        }

        // 3. 브라우저가 화면을 100% 다 그리고 나면, 애니메이션을 다시 켜줍니다.
        window.requestAnimationFrame(function() {
          setTimeout(function() {
            document.body.classList.remove('preload-theme');
          }, 100);
        });
      })();
















/* =========================================================
   [최종 종결] 팝업 바운스 스크롤 & 배경 화면 덜컹거림 완벽 차단
========================================================= */
/* =========================================================
   [최종 종결] 팝업 바운스 스크롤 & 짧은 팝업 배경 스크롤 허용
========================================================= */
/* =========================================================
   [최종 종결] 팝업 바운스 스크롤 & 모바일/PC 짧은 팝업 배경 스크롤 완벽 허용
========================================================= */
/* =========================================================
   [전 기기 통합] 애플(iOS) 스타일 정밀 바운스 스크롤 (애플 기기 포함 강제 적용)
========================================================= */
// =========================================================
// [전 기기 통합] 애플(iOS) 스타일 정밀 바운스 스크롤 (여백 스크롤 새어나감 완벽 차단)
// =========================================================
(function() {
    function rubberBand(distance, dimension) {
        const c = 0.65; 
        return (distance * dimension * c) / (dimension + distance * c);
    }

    function isScrollable(el) {
        return (el.scrollHeight - el.clientHeight) > 5;
    }

    function updateOverscrollTrap(target) {
        if (isScrollable(target)) {
            target.style.setProperty('overscroll-behavior', 'contain', 'important');
            if (target.parentElement) target.parentElement.style.setProperty('overscroll-behavior', 'contain', 'important');
        } else {
            target.style.setProperty('overscroll-behavior', 'auto', 'important');
            if (target.parentElement) target.parentElement.style.setProperty('overscroll-behavior', 'auto', 'important');
        }
    }

    let startY = 0;
    let isPulling = false;

    // 🚀 헬퍼 함수: 마우스/터치가 '팝업 전체(빈 공간 포함)'에 있는지 확인하고 알맹이를 찾음
    function getScrollTarget(e) {
        const popup = e.target.closest('.reference-tooltip, .floating-footnote-content');
        if (!popup) return null;
        return popup.querySelector('.ref-inner-scroll, .footnote-inner-scroll');
    }

    // 📱 터치 디바이스 제어
    document.addEventListener('touchstart', function(e) {
        const target = getScrollTarget(e);
        if (!target) return;

        updateOverscrollTrap(target);
        if (!isScrollable(target)) return; 

        startY = e.touches[0].clientY;
        target.style.transition = 'none';
        isPulling = false;
    }, { passive: true });

    document.addEventListener('touchmove', function(e) {
        const popup = e.target.closest('.reference-tooltip, .floating-footnote-content');
        if (!popup) return; // 팝업 밖이면 패스

        const target = popup.querySelector('.ref-inner-scroll, .footnote-inner-scroll');

        // 🚀 핵심: 팝업 안쪽(빈 여백 포함)을 터치했는데 스크롤 알맹이가 없거나 스크롤이 불가능하면 뒷배경 스크롤 원천 차단!
        if (!target || !isScrollable(target)) {
            if (e.cancelable) e.preventDefault();
            return;
        }

        const clientY = e.touches[0].clientY;
        const deltaY = clientY - startY;

        const isAtTop = target.scrollTop <= 0;
        const isAtBottom = (target.scrollTop + target.clientHeight + 1) >= target.scrollHeight;

        if ((isAtTop && deltaY > 0) || (isAtBottom && deltaY < 0)) {
            if (e.cancelable) e.preventDefault(); 

            isPulling = true;
            const move = rubberBand(Math.abs(deltaY), target.clientHeight) * Math.sign(deltaY);
            target.style.transform = `translateY(${move}px)`;
        } else {
            // 정상 스크롤 중에도 이벤트가 뒤로 새는 것을 방어 (overscroll-behavior 백업)
            e.stopPropagation();
        }
    }, { passive: false });

    document.addEventListener('touchend', function(e) {
        const target = getScrollTarget(e);
        if (!target || !isPulling) return;

        isPulling = false;
        target.style.transition = 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)';
        target.style.transform = 'translateY(0)';
    });

    // 💻 마우스 휠 (윈도우/맥 공통) 제어
    let wheelTimer = null;
    let currentOffset = 0;

    document.addEventListener('wheel', function(e) {
        const popup = e.target.closest('.reference-tooltip, .floating-footnote-content');
        if (!popup) return; // 팝업 밖이면 패스

        const target = popup.querySelector('.ref-inner-scroll, .footnote-inner-scroll');

        // 🚀 핵심: 팝업 빈 공간(여백)에 마우스가 있을 때 휠을 굴리면 무조건 뒷배경 스크롤 차단!
        if (!target || !isScrollable(target)) {
            if (e.cancelable) e.preventDefault();
            return;
        }

        const isAtTop = target.scrollTop <= 0;
        const isAtBottom = (target.scrollTop + target.clientHeight + 1) >= target.scrollHeight;

        if ((isAtTop && e.deltaY < 0) || (isAtBottom && e.deltaY > 0)) {
            if (e.cancelable) e.preventDefault();

            currentOffset -= (e.deltaY * 0.4); 
            if (currentOffset > 80) currentOffset = 80;
            if (currentOffset < -80) currentOffset = -80;

            target.style.transition = 'transform 0.15s ease-out';
            target.style.transform = `translateY(${currentOffset}px)`;

            clearTimeout(wheelTimer);
            wheelTimer = setTimeout(() => {
                target.style.transition = 'transform 0.5s cubic-bezier(0.16, 1, 0.3, 1)';
                target.style.transform = 'translateY(0)';
                currentOffset = 0;
            }, 120);
        } else {
            // 이벤트 버블링 차단
            e.stopPropagation();
        }
    }, { passive: false });
})();



