b:if.script:
//
document.addEventListener("DOMContentLoaded", function() {
  const board = document.getElementById('custom-notice-board');
  const noticeLabel = encodeURIComponent('공지');
  const feedUrl = `/feeds/posts/default/-/${noticeLabel}?alt=json&max-results=3`;

  fetch(feedUrl)
    .then(res => res.json())
    .then(data => {
      // 공지글이 없으면 스켈레톤을 지우고 게시판을 완전히 숨깁니다
      if (!data.feed.entry || data.feed.entry.length === 0) {
        board.style.display = 'none';
        board.classList.remove('skeleton-ui');
        return;
      }

      let noticeHtml = '<ul class="notice-list">';
      data.feed.entry.forEach(entry => {
        let title = entry.title.$t;
        let link = entry.link.find(l => l.rel === 'alternate').href.split(/[?#]/)[0];
        let date = new Date(entry.published.$t).toLocaleDateString('ko-KR', {year: 'numeric', month: '2-digit', day: '2-digit'}).slice(0, -1);

        noticeHtml += `
          <li>
            <a href="${link}">
              <span class="notice-badge">공지</span>
              <span class="notice-title">${title}</span>
              <span class="notice-date">${date}</span>
            </a>
          </li>
        `;
      });
      noticeHtml += '</ul>';

      // 1. 뼈대(스켈레톤) 클래스 제거 및 임시 높이 초기화
      board.classList.remove('skeleton-ui');
      board.style.minHeight = 'auto';

      // 2. 실제 데이터 삽입
      board.innerHTML = noticeHtml;

      // 3. 통통 튀며 등장하는 팝(Pop) 애니메이션 연결 (기존 UI와 동기화)
      board.style.opacity = '0';
      board.style.animation = 'popInElements 0.5s cubic-bezier(0.175, 0.885, 0.32, 1.275) forwards';
    })
    .catch(err => {
      console.error('공지사항 로딩 실패:', err);
      board.style.display = 'none';
      board.classList.remove('skeleton-ui');
    });
});
