body.script:
//
document.addEventListener("DOMContentLoaded", function() {





  // ==========================================
  // 1 & 2. 플로팅 목차 (화면 이탈 방지 & 스마트 자동 펼침)
  // ==========================================

// ==========================================
  // 1 & 2. 플로팅 목차 (화면 이탈 방지 & 스마트 자동 펼침)
const postBody = document.body.classList.contains('item-view') ? document.querySelector('.post-body') : null;
if (postBody) {
  const headings = postBody.querySelectorAll('h2, h3, h4, h5');

    if (headings.length > 0) {

      // 🚀 [안드로이드 버그 완벽 차단] CSS에 의존하지 않고 JS로 본문에 직접 번호 하드코딩
      let hCounts = { 2: 0, 3: 0, 4: 0, 5: 0 };
      headings.forEach(heading => {
        if (heading.querySelector('.js-heading-num')) return; // 중복 방지
        const lvl = parseInt(heading.tagName.substring(1));
        hCounts[lvl]++;
        for (let i = lvl + 1; i <= 5; i++) hCounts[i] = 0; 

        let numStr = hCounts[2];
        if (lvl === 2) numStr += ".";
        if (lvl >= 3) numStr += "." + hCounts[3];
        if (lvl >= 4) numStr += "." + hCounts[4];
        if (lvl >= 5) numStr += "." + hCounts[5];
        numStr += " ";

        const numSpan = document.createElement('span');
        numSpan.className = 'js-heading-num';
        numSpan.textContent = numStr;
        numSpan.style.color = '#3182F6';
        numSpan.style.marginRight = '6px';
        numSpan.style.pointerEvents = 'none'; 

        heading.insertBefore(numSpan, heading.firstChild);
      });

      const wrapper = document.createElement('div');




      wrapper.id = 'toc-wrapper';
      const header = document.createElement('div');
      header.className = 'toc-header';
      header.innerHTML = `
        <span class="toc-title">목차</span>
        <div class="toc-header-btns">
          <button class="toc-btn toc-reset-btn" title="맨 위로 고정">↺</button>
          <button class="toc-btn toc-toggle-btn" title="접기/펴기">—</button>
        </div>
      `;
      const tocBody = document.createElement('div');
      tocBody.className = 'toc-body';

      const rootUl = document.createElement('ul');
      let uls = { 2: rootUl }; let currentLevel = 2;
      headings.forEach((heading, index) => {
        const level = parseInt(heading.tagName.substring(1));
        heading.id = heading.id || 'heading-' + index;
        const li = document.createElement('li');
        const a = document.createElement('a');
        a.href = '#' + heading.id;
        // 사용자가 직접 입력한 숫자(1. 어쩌고 등)는 살리고, 자동 생성된 숫자/아이콘만 쏙 빼서 가져오기
let clone = heading.cloneNode(true);
let autoNum = clone.querySelector('.js-heading-num');
let iconNode = clone.querySelector('.section-toggle-icon');
if (autoNum) autoNum.remove();
if (iconNode) iconNode.remove();
a.innerHTML = clone.innerHTML.trim(); // 👈 수식 뼈대(HTML)까지 안전하게 복사!



        // [완벽 수정판] 목차 항목 클릭 시 접힌 섹션 자동 펼치기 및 이동
        a.addEventListener('click', function(e) {
          e.preventDefault(); 
          const href = this.getAttribute('href');
          const targetId = decodeURIComponent(href.substring(1));
          const targetHeading = document.getElementById(targetId) || document.getElementById(href.substring(1));

          if (targetHeading) {
            targetHeading.classList.remove('heading-collapsed');

            let prevNode = targetHeading.previousElementSibling;
            let targetLevel = parseInt(targetHeading.tagName.substring(1));

            while (prevNode) {
              if (prevNode.tagName && /^H[1-6]$/i.test(prevNode.tagName)) {
                const prevLevel = parseInt(prevNode.tagName.substring(1));
                if (prevLevel < targetLevel) {
                  prevNode.classList.remove('heading-collapsed');
                  targetLevel = prevLevel; 
                }
              }
              prevNode = prevNode.previousElementSibling;
            }

            if (typeof window.syncFolding === 'function') window.syncFolding();

            targetHeading.scrollIntoView({ behavior: 'smooth', block: 'start' });
            history.pushState(null, null, href);
          }
        });

        li.appendChild(a);
        if (level > currentLevel) {
          for (let i = currentLevel + 1; i <= level; i++) {
            const newUl = document.createElement('ul');
            const parentUl = uls[i - 1] || rootUl;
            let parentLi = parentUl.lastElementChild || document.createElement('li');
            if (!parentUl.lastElementChild) parentUl.appendChild(parentLi);
            parentLi.appendChild(newUl);
            uls[i] = newUl;
          }
        }
        let targetUl = uls[level] || rootUl;
        targetUl.appendChild(li);
        currentLevel = level;
        for (let i = level + 1; i <= 6; i++) uls[i] = null;
      });

      tocBody.appendChild(rootUl);
      wrapper.appendChild(header);
      wrapper.appendChild(tocBody);
      document.body.appendChild(wrapper);

      let xOffset = 0, yOffset = 0;
      let isDragging = false, currentX, currentY, initialX, initialY;

      const resetPos = () => { 
        xOffset = 0; yOffset = 0;
        wrapper.style.transform = `translate3d(0, 0, 0)`;
      };

      header.addEventListener("mousedown", dragStart);

// 드래그가 끝날 때 클래스 제거
      const dragEnd = () => {
        isDragging = false;
        wrapper.classList.remove('dragging'); 
      };

      header.addEventListener("mousedown", dragStart);
      document.addEventListener("mouseup", dragEnd);
      document.addEventListener("mousemove", drag);
      header.addEventListener("touchstart", dragStart, {passive: true});
      document.addEventListener("touchend", dragEnd);
      document.addEventListener("touchmove", drag, {passive: false});

      function dragStart(e) {
        if (e.target.closest('.toc-btn')) return;

        // 🚀 핵심: 드래그 시작 시 CSS 강제 종료 클래스 추가
        wrapper.classList.add('dragging');

        initialX = (e.type === "touchstart" ? e.touches[0].clientX : e.clientX) - xOffset;
        initialY = (e.type === "touchstart" ? e.touches[0].clientY : e.clientY) - yOffset;
        if (!wrapper.classList.contains('folded')) isDragging = true;
      }




      function drag(e) {
        if (isDragging && !wrapper.classList.contains('folded')) {
          e.preventDefault();
          currentX = (e.type === "touchmove" ? e.touches[0].clientX : e.clientX) - initialX;
          currentY = (e.type === "touchmove" ? e.touches[0].clientY : e.clientY) - initialY;

          const maxX = 30; 
          const minX = -(window.innerWidth - wrapper.offsetWidth - 30); 
          const maxY = window.innerHeight - wrapper.offsetHeight - 80; 
          const minY = -80; 

          if (currentX > maxX) currentX = maxX;
          if (currentX < minX) currentX = minX;
          if (currentY > maxY) currentY = maxY;
          if (currentY < minY) currentY = minY;

          xOffset = currentX; yOffset = currentY;
          wrapper.style.transform = `translate3d(${currentX}px, ${currentY}px, 0)`;
        }
      }




header.querySelector('.toc-toggle-btn').onclick = () => {
        wrapper.classList.toggle('folded');
        const isFolded = wrapper.classList.contains('folded');
        header.querySelector('.toc-toggle-btn').textContent = isFolded ? '+' : '—';

        // ✨ 핵심 추가: 목차가 접혔는지 여부를 body에 알려서 톱니바퀴가 도망가게 함
        if (isFolded) {
          document.body.classList.add('toc-folded');
          wrapper.style.transform = ''; 
        } else {
          document.body.classList.remove('toc-folded');
          wrapper.style.transform = `translate3d(${xOffset}px, ${yOffset}px, 0)`;
        }
      };






      header.querySelector('.toc-reset-btn').onclick = resetPos;
    }
  }




// ==========================================
  // 3. 모바일 최적화 각주 (모달 팝업 및 중첩 각주 완벽 지원)
  // ==========================================
  document.addEventListener('click', function(e) {
    const targetEl = e.target.nodeType === 3 ? e.target.parentNode : e.target;
    // ^(시작) 대신 *(포함)으로 변경하여 절대경로 변환 버그 원천 차단
    const ref = targetEl.closest('a[href*="#fn"]'); 

    if (!ref) return;
    const hrefAttr = ref.getAttribute('href') || '';
    if (hrefAttr.includes('#fnref') || ref.classList.contains('footnote-backref')) return;

    e.preventDefault(); 
    e.stopPropagation();



    // 🚀 핵심 버그 해결: 기존 팝업을 삭제하기 '직전'에 클릭한 각주의 현재 좌표(위치)를 미리 기억해둠!

    // 🚀 핵심 버그 해결: 기존 팝업을 삭제하기 '직전'에 클릭한 각주의 현재 좌표(위치)를 미리 기억해둠!
    const rect = ref.getBoundingClientRect();

    const existingPopup = document.querySelector('.floating-footnote-content');
    if (existingPopup) {
      // 이미 열려있는 팝업과 같은 각주를 누르면 닫기만 하고 종료
      if (existingPopup.dataset.refId === ref.hash) {
        existingPopup.remove();
        return;
      }
      existingPopup.remove(); // 기존 팝업 삭제
    }

 // 🚀 모바일(?m=1) 절대경로 해시 파싱 버그 완벽 해결
const hashVal = ref.hash ? ref.hash : ('#' + ref.getAttribute('href').split('#')[1]);
const targetId = hashVal.substring(1);
const targetLi = document.getElementById(targetId);

    if (targetLi) {
      const popup = document.createElement('div');
      popup.className = 'floating-footnote-content';
      popup.dataset.refId = ref.hash;

      const innerScroll = document.createElement('div');
      innerScroll.className = 'footnote-inner-scroll';
      innerScroll.innerHTML = targetLi.innerHTML;

      // 팝업 안의 돌아가기 링크 제거
      const backref = innerScroll.querySelector('a.footnote-backref, a[href^="#fnref"]');
      if (backref) backref.remove();

      const closeBtn = document.createElement('span');
      closeBtn.innerHTML = '×';
      closeBtn.className = 'footnote-close-btn';
      closeBtn.onclick = () => popup.remove();

      popup.appendChild(closeBtn);
      popup.appendChild(innerScroll);
      document.body.appendChild(popup);

      const popupWidth = popup.offsetWidth;
      const popupHeight = popup.offsetHeight; 

      // 미리 기억해둔 rect 좌표를 사용해 팝업 띄울 위치 계산
      let topPos = rect.bottom + window.scrollY + 10;
      let leftPos = rect.left + window.scrollX;

      // 화면 오른쪽 이탈 방지
      if (leftPos + popupWidth > window.innerWidth - 15) {
        leftPos = window.innerWidth - popupWidth - 15; 
      }
      if (leftPos < 15) leftPos = 15;

      // 화면 아래쪽 이탈 방지 (위로 띄움)
      if (rect.bottom + popupHeight + 15 > window.innerHeight) {
        topPos = rect.top + window.scrollY - popupHeight - 10;
        if (topPos < window.scrollY + 10) topPos = window.scrollY + 10;
      }

      popup.style.top = topPos + 'px';
      popup.style.left = leftPos + 'px';

      // 팝업창 내부에 있는 수학 수식도 다시 렌더링 (MathJax 동기화)
      if (window.MathJax && MathJax.typesetPromise) {
        MathJax.typesetPromise([popup]);
      }
    }
  });


  // PC 클릭 및 모바일 터치 완벽 대응
  const closeFootnotePopup = function(e) {
// 🚀 링크 시작(^)이 아닌 포함(*)으로 변경하여 모바일 터치 오작동 차단
if (!e.target.closest('.floating-footnote-content') && !e.target.closest('a[href*="#fn"]')) {
      const existingPopup = document.querySelector('.floating-footnote-content');
      if (existingPopup) existingPopup.remove();
    }
  };

  document.addEventListener('click', closeFootnotePopup);
  document.addEventListener('touchstart', closeFootnotePopup, { passive: true });









  // ==========================================
  // 5. 글 섹션 초기 로딩 접기 & 클릭 제어 (강력한 동기화)
  // ==========================================
  if (postBody) {
    const toggleHeadings = postBody.querySelectorAll('h2, h3, h4');

    toggleHeadings.forEach(heading => {
      heading.style.cursor = 'pointer';
      const icon = document.createElement('span');
      icon.className = 'section-toggle-icon';
      icon.textContent = '▼';
      heading.appendChild(icon);
      heading.classList.add('heading-collapsed'); 
    });

    const syncFolding = () => {
      let skipLevel = 0; 
      let node = postBody.firstElementChild;

      while(node) {
        if (node.id === 'toc-wrapper') { node = node.nextElementSibling; continue; }
        const tag = node.tagName;
        const isHeading = tag && /^H[1-6]$/i.test(tag);
        const level = isHeading ? parseInt(tag.substring(1)) : 7;

        if (isHeading) {
          if (skipLevel > 0 && level <= skipLevel) {
            skipLevel = 0; 
          }
          if (skipLevel > 0) {
            node.classList.add('hidden-section-content');
          } else {
            node.classList.remove('hidden-section-content');
            if (node.classList.contains('heading-collapsed')) {
              skipLevel = level;
            }
          }
        } else {
          if (skipLevel > 0) {
            node.classList.add('hidden-section-content');
          } else {
            node.classList.remove('hidden-section-content');
          }
        }
        node = node.nextElementSibling;
      }
    };

    window.syncFolding = syncFolding;
    syncFolding();

    toggleHeadings.forEach(heading => {
      heading.addEventListener('click', function() {
        this.classList.toggle('heading-collapsed');
        syncFolding();
      });
    });

// 🚀 [최적화] MathJax v3 로딩 완료 시점을 정확히 추적하여 폴딩 동기화 (불필요한 1초 대기 삭제)
    if (window.MathJax && MathJax.startup && MathJax.startup.promise) {
      MathJax.startup.promise.then(() => {
        if (typeof window.syncFolding === 'function') window.syncFolding();
      });
    } else {
      // 수식이 아예 없는 페이지를 위한 안전장치
      setTimeout(() => { if (typeof window.syncFolding === 'function') window.syncFolding(); }, 300);
    }
  }


// ==========================================
// [옵시디언 호환 + 제목 넘버링] 전역 콜아웃 변환 (완벽 통합판)
// ==========================================


// ==========================================
  // [옵시디언 호환 + 제목 넘버링] 전역 콜아웃 변환 (클릭 시 Lightbox 팝업 지원)
  // ==========================================
  // 1. 팝업창 HTML 구조 바디 맨 뒤에 주입 (한 번만 실행)
  if (!document.getElementById('callout-modal-overlay')) {
    const modalHTML = `
      <div id="callout-modal-overlay">
        <div id="callout-modal-box">
          <button id="callout-modal-close" title="닫기 (Esc)">✕</button>
          <div id="callout-modal-body"></div>
        </div>
      </div>
    `;
    document.body.insertAdjacentHTML('beforeend', modalHTML);

    // 닫기 로직 함수
    const closeModal = () => {
      document.getElementById('callout-modal-overlay').classList.remove('open');
      document.body.classList.remove('callout-modal-open');
    };

    // 이벤트 바인딩 (X버튼, 배경클릭, Esc키)
    document.getElementById('callout-modal-close').onclick = closeModal;
    document.getElementById('callout-modal-overlay').onclick = (e) => {
      if (e.target === document.getElementById('callout-modal-overlay')) closeModal();
    };
    document.addEventListener('keydown', (e) => {
      if (e.key === 'Escape' && document.getElementById('callout-modal-overlay').classList.contains('open')) closeModal();
    });
  }

 window.initCallouts = function(container = document) {
    let maxLimit = 200; 
    let count = 0;

    while (count < maxLimit) {
        let el = container.querySelector('.post-body blockquote:not(.callout):not(.not-callout), .post-body > p:not(.callout):not(.not-callout), .post-body div:not(.callout):not(.not-callout)');

        if (!el) break; 
        count++;

        let html = el.innerHTML.trim();

        // 🚀 [근본 해결 1] 텅 빈 <p> 갭이 생기지 않도록, 제목을 감싸는 <p>와 </p>까지 한 번에 묶어서 추출합니다.
        let titleRegex = /^(?:<p>)?\s*\[!([^\]]+)\]([+-]?)([\s\S]*?)(?:<br\s*\/?>|<\/p>|\n|$)/i;
        let match = html.match(titleRegex);

        if (match) {
            let fullMatch = match[0]; 
            let type = match[1].toLowerCase().trim();
            let collapseSign = match[2]; 
            let titleHtml = match[3].trim(); 


			const numberedTypes = ['definition', '정의', 'theorem', '정리', 'lemma', '보조정리', 'corollary', '따름정리', 'example', '예시','증명', 'proof'];
                    const rawType = match[1].trim(); // 사용자가 적은 '[!정리]' 안의 텍스트

                    if (!titleHtml || titleHtml === rawType) {
                        if (numberedTypes.includes(type)) {
                            // 1. 자동 넘버링이 붙는 종류라면 텍스트를 완전히 비움 (CSS가 '정리 1.'을 알아서 띄움)
                            titleHtml = ''; 
                        } else {
                            // 2. 증명(Proof), 노트(Note) 등 번호가 없는 일반 콜아웃은 원래대로 기본 이름을 띄움
                            titleHtml = rawType.charAt(0).toUpperCase() + rawType.slice(1);
                        }
                    }



            // 🚀 [근본 해결 2] 제목에 $$ 블록 수식을 썼더라도, 화면에 뿌리기 전에 JS가 강제로 인라인($) HTML 속성으로 조작해 버립니다.
            titleHtml = titleHtml.replace(/display="block"/g, 'display="inline"').replace(/display="true"/g, 'display="false"').replace(/class="math display"/g, 'class="math inline"').replace(/class="katex-display"/g, 'class="katex"').replace(/style="[^"]*display:[^;]*block[^"]*"/gi, 'style="display:inline"');
            let localPrefix = "";
            let candidateTexts = [];

            let bodyH1 = el.closest('.post-body') ? el.closest('.post-body').querySelector('h1') : null;
            if (bodyH1) candidateTexts.push(bodyH1.textContent);

            let postContainer = el.closest('.post-outer-container') || el.closest('.post');
            let postTitle = postContainer ? postContainer.querySelector('.post-title') : null;
            if (postTitle) candidateTexts.push(postTitle.textContent);

            candidateTexts.push(document.title);

            for (let i = 0; i < candidateTexts.length; i++) {
                if (!candidateTexts[i]) continue;
                let titleMatch = candidateTexts[i].match(/([0-9]+[-.][0-9]+(?:[-.][0-9]+)*)/);
                if (titleMatch) {
                    localPrefix = titleMatch[1].split(/[-.]/).map(n => parseInt(n, 10)).join('.') + ".";
                    break; 
                }
            }

            el.classList.add('callout');
            el.setAttribute('data-callout', type);

            // 🚀 [근본 해결 3] 본문에서 제목 코드를 도려낼 때, <p></p> 찌꺼기가 남지 않게 깔끔하게 분리
            let innerHTML = html.replace(fullMatch, '').trim();

            // 만약 추출 과정에서 앞쪽 <p>는 잘렸는데 뒤에 </p>가 없는 경우 (Pandoc 줄바꿈 변수 방어) 짝을 맞춰줍니다.
            if (/^<p>/i.test(fullMatch.trim()) && !/<\/p>$/i.test(fullMatch.trim())) {
                innerHTML = '<p>' + innerHTML;
            }

            // 혹시 모를 맨 앞쪽 엔터 찌꺼기 청소
            innerHTML = innerHTML.replace(/^(<br\s*\/?>|\n)+/i, '').trim();

            el.innerHTML = '';

            let titleDiv = document.createElement('div');
            titleDiv.className = 'callout-title';

            let foldIconHtml = '';
            if (collapseSign === '+' || collapseSign === '-') {
                el.classList.add('is-collapsible');
                if (collapseSign === '-') el.classList.add('is-collapsed');
                foldIconHtml = '<span class="callout-fold-icon">▼</span>';

                titleDiv.addEventListener('click', function(e) {
                    if (e.target.closest('a')) return;
                    el.classList.toggle('is-collapsed');
                });
            }

            titleDiv.innerHTML = foldIconHtml + '<div class="callout-title-inner" ' + (localPrefix ? 'data-prefix="' + localPrefix + '"' : '') + '>' + titleHtml + '</div>';

            let contentDiv = document.createElement('div');
            contentDiv.className = 'callout-content';
            contentDiv.innerHTML = innerHTML;

            el.appendChild(titleDiv);
            el.appendChild(contentDiv);
        } else {
            el.classList.add('not-callout');
        }
    }
};

  // 처음 로딩 시 실행
  initCallouts();


// ==========================================
  // 🚀 [옵시디언 호환] ==형광펜== 문법 자동 파싱
  // ==========================================
window.parseObsidianHighlights = function() {
  document.querySelectorAll('.post-body').forEach(body => {
    // 1. 본문 안의 모든 '텍스트 노드'만 안전하게 추출 (HTML 구조 보존)
    const walker = document.createTreeWalker(body, NodeFilter.SHOW_TEXT, null, false);
    const nodesToReplace = [];
    let node;

    while (node = walker.nextNode()) {
      const parentTag = node.parentNode.tagName.toUpperCase();
      // 코드블록이나 스크립트 내부 등은 무시
      if (['CODE', 'PRE', 'SCRIPT', 'STYLE'].includes(parentTag) || node.parentNode.closest('mjx-container')) continue;

      // 텍스트에 '=='가 포함된 노드만 후보로 등록
      if (node.nodeValue.includes('==')) {
        nodesToReplace.push(node);
      }
    }

    nodesToReplace.forEach(txtNode => {
      const text = txtNode.nodeValue;

      // 🚀 [핵심 로직] 수식($...$)과 형광펜(==...==)을 동시 탐색하는 정규식
      // 매칭 그룹 1: 수식 ($$수식$$ 또는 $수식$)
      // 매칭 그룹 2: 형광펜 내부 텍스트
      const regex = /(\$\$[\s\S]+?\$\$|\$(?:\\.|[^$\\])+?\$)|==([\s\S]+?)==/g;

      if (!regex.test(text)) return;

      const fragment = document.createDocumentFragment();
      let lastIndex = 0;
      regex.lastIndex = 0; // test() 호출 후 인덱스 초기화

      let match;
      while ((match = regex.exec(text)) !== null) {
        // 매칭된 부분 이전의 일반 텍스트 보존
        if (match.index > lastIndex) {
          fragment.appendChild(document.createTextNode(text.substring(lastIndex, match.index)));
        }

        if (match[1]) {
          // ✅ 수식($a==b$)이 먼저 잡힌 경우: 형광펜으로 바꾸지 않고 '그대로' 텍스트로 보존 (보호 구역)
          fragment.appendChild(document.createTextNode(match[1]));
        } else if (match[2]) {
          // ✅ 형광펜(==텍스트==)이 잡힌 경우: <mark> 태그로 변환
          const mark = document.createElement('mark');
          mark.className = 'obsidian-highlight';
          mark.textContent = match[2];
          fragment.appendChild(mark);
        }
        lastIndex = regex.lastIndex;
      }

      // 남은 자투리 텍스트 마저 이어붙이기
      if (lastIndex < text.length) {
        fragment.appendChild(document.createTextNode(text.substring(lastIndex)));
      }

      // 기존 텍스트를 파싱된 조각들로 부드럽게 교체 (이벤트 리스너 파괴 없음!)
      txtNode.parentNode.replaceChild(fragment, txtNode);
    });
  });
};







window.initCodeBlocks = function() {
    // ① Pandoc 스타일(sourceCode) 변환 로직
    document.querySelectorAll('pre.sourceCode').forEach(pre => {
      const code = pre.querySelector('code.sourceCode');
      if (code) {
        const langClass = Array.from(pre.classList).find(c => c !== 'sourceCode' && c !== 'numberSource');
        const lang = langClass ? 'language-' + langClass : 'language-none';
        const rawText = code.textContent;

        const newPre = document.createElement('pre');
        newPre.className = lang;
        const newCode = document.createElement('code');
        newCode.className = lang;
        newCode.textContent = rawText;
        newPre.appendChild(newCode);

        const parent = pre.parentElement;
        if (parent && parent.classList.contains('sourceCode') && parent.tagName === 'DIV') {
          parent.parentNode.replaceChild(newPre, parent);
        } else {
          pre.parentNode.replaceChild(newPre, pre);
        }
      }
    });

    // 🚀 ② [핵심 패치] 사용자가 수동으로 적은 <pre><code> 태그 보정 (none으로 변경)
    document.querySelectorAll('.post-body pre').forEach(pre => {
      if (!pre.className || !pre.className.includes('language-')) {
        pre.className = 'language-none'; // Prism 툴바 에러를 막는 공식 방식
      }
      const code = pre.querySelector('code');
      if (code && (!code.className || !code.className.includes('language-'))) {
        code.className = 'language-none';
      }
    });

    // 형광펜 파싱 먼저 실행 후 코드 색칠
    if (typeof parseObsidianHighlights === 'function') parseObsidianHighlights();
    if (window.Prism) {
      Prism.highlightAll(); // 불량 plaintext 강제 주입 코드 제거 완료
    }
  };




// ==========================================
  // 7. 🚀 Overleaf 연동 버튼을 "먼저" 등록 (Open in Overleaf)
  // ==========================================
  if (window.Prism && Prism.plugins.toolbar) {
    Prism.plugins.toolbar.registerButton('latex-overleaf', function(env) {
      if (env.language !== 'latex' && env.language !== 'tex') return null;

      const btn = document.createElement('button');
      btn.innerHTML = '<span style="color:#4CA746; margin-right:4px;">↗</span>Overleaf';
      btn.className = 'latex-overleaf-btn';

      btn.addEventListener('click', function() {
        let rawCode = env.element.textContent.trim();

        let compileCode = rawCode;
        if (!rawCode.includes('\\documentclass')) {
          compileCode = "\\documentclass{article}\n\\usepackage[utf8]{inputenc}\n\\usepackage{amsmath, amssymb,kotex}\n\\usepackage{tikz}\n\\usepackage{geometry}\n\\geometry{a4paper, margin=1in}\n\n\\begin{document}\n\n" + rawCode + "\n\n\\end{document}";
        }

        const form = document.createElement('form');
        form.method = 'POST';
        form.action = 'https://www.overleaf.com/docs';
        form.target = '_blank';

        const input = document.createElement('input');
        input.type = 'hidden';
        input.name = 'snip';
        input.value = compileCode;

        form.appendChild(input);
        document.body.appendChild(form);
        form.submit();
        document.body.removeChild(form);
      });

      return btn;
    });
  }




  // 🚀 제미나이 스타일 아이콘 카피 버튼 등록
  if (window.Prism && Prism.plugins.toolbar) {
    Prism.plugins.toolbar.registerButton('copy-to-clipboard', function(env) {
      const btn = document.createElement('button');
      btn.className = 'copy-code-btn';







      // 제미나이 스타일의 클립보드 및 체크 아이콘 (체크 기호 회색 #8B95A1 변경 완료)
      const clipboardIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="width:16px;height:16px;vertical-align:middle;"><rect x="9" y="9" width="13" height="13" rx="2" ry="2"></rect><path d="M5 15H4a2 2 0 0 1-2-2V4a2 2 0 0 1 2-2h9a2 2 0 0 1 2 2v1"></path></svg>`;
// #CED4DA 또는 #E5E8EB 중 마음에 드는 밝기로 선택하세요.
const checkIcon = `<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5" stroke-linecap="round" stroke-linejoin="round" style="width:16px;height:16px;vertical-align:middle;color:#CED4DA;"><polyline points="20 6 9 17 4 12"></polyline></svg>`;

      btn.innerHTML = clipboardIcon;

      btn.addEventListener('click', function() {
        const text = env.element.textContent;
        navigator.clipboard.writeText(text).then(function() {
          btn.innerHTML = checkIcon;
          // 💡 작성해두신 CSS(회색 배경)가 정상 작동하도록 상태 속성 부여
          btn.setAttribute('data-copy-state', 'copy-success'); 
          setTimeout(function() {
            btn.innerHTML = clipboardIcon;
            btn.removeAttribute('data-copy-state');
          }, 2000);
        });
      });
      return btn;
    });



  }

  // 🚀 버튼 세팅이 다 끝난 후, 제일 마지막에 코드 색칠 실행!
  initCodeBlocks();


// 본문 이미지 네이티브 지연 로딩 강제화 (스크롤 성능 향상)
  document.querySelectorAll('.post-body img').forEach(img => {
      if(!img.hasAttribute('loading')) img.setAttribute('loading', 'lazy');
  });





 });










