//
  document.addEventListener("DOMContentLoaded", function() {
    // 마크다운/HTML에서 Prism이 인식하는 기본 형태인 <pre> 안의 <code> 태그를 모두 수집
    const codeBlocks = document.querySelectorAll('pre code');

    // 만약 매우 구형 브라우저라 Observer를 지원하지 않으면 기존처럼 한 번에 모두 렌더링
    if (!window.IntersectionObserver) {
      Prism.highlightAll();
      return;
    }

    const observer = new IntersectionObserver((entries, obs) => {
      entries.forEach(entry => {
        // 코드 블록이 화면에 들어왔을 때
        if (entry.isIntersecting) {
          // 해당 블록만 하이라이팅 실행 (병목 제거)
          Prism.highlightElement(entry.target);

          // 한 번 색칠한 블록은 더 이상 관찰하지 않음 (메모리 확보)
          obs.unobserve(entry.target);
        }
      });
    }, { 
      // 최적화 디테일: 화면에 닿기 200px 전부터 미리 렌더링을 시작하여
      // 사용자가 스크롤을 빨리 내려도 색칠되지 않은 원본 코드가 보이지 않도록 방어
      rootMargin: "200px 0px" 
    });

    // 수집한 모든 코드 블록에 감시자(Observer) 부착
    codeBlocks.forEach(block => observer.observe(block));
  });
