body.script:
//
document.addEventListener("DOMContentLoaded", () => {
  const seriesBoxes = document.querySelectorAll('.series-box');

  seriesBoxes.forEach(box => {
    const tag = box.getAttribute('data-tag');
    if (!tag) return;

    const feedUrl = `/feeds/posts/summary/-/${encodeURIComponent(tag)}?alt=json&amp;max-results=50`;
    const cacheKey = 'series_cache_' + tag;
    const cachedData = sessionStorage.getItem(cacheKey);

    const renderSeries = (data) => {
      if (!data.feed.entry) return;

      const currentUrl = window.location.href.split('#')[0].split('?')[0];
      let entries = data.feed.entry.reverse();
      let currentIndex = -1;

      let listHtml = '<ul class="series-list">';
      entries.forEach((entry, index) => {
        let title = entry.title.$t;
        let link = entry.link.find(l => l.rel === 'alternate').href;
        let isCurrent = currentUrl === link.split('#')[0].split('?')[0];

        if (isCurrent) currentIndex = index + 1;

        listHtml += `
          <li class="${isCurrent ? 'current' : ''}">
            <a href="${link}">${index + 1}. ${title}</a>
          </li>`;
      });
      listHtml += '</ul>';

      box.innerHTML = `
        <div class="series-header">
          <span class="series-badge">SERIES</span>
          <h4 class="series-title">'${tag}' 시리즈</h4>
          <span class="series-count">${currentIndex !== -1 ? currentIndex : '-'}/${entries.length}</span>
        </div>
        <div class="series-body">
          ${listHtml}
        </div>
      `;
    };

    if (cachedData) {
      renderSeries(JSON.parse(cachedData));
    } else {
      fetch(feedUrl)
        .then(response => response.json())
        .then(data => {
          sessionStorage.setItem(cacheKey, JSON.stringify(data));
          renderSeries(data);
        })
        .catch(err => console.error(err));
    }
  });
});
