document.addEventListener("DOMContentLoaded", function() {
    // 🚀 모든 태그 요소(본문 및 사이드바 포함) 가져오기
    const labelLinks = document.querySelectorAll('.post-labels a, .byline.post-labels a, .Label a');
    if (labelLinks.length === 0) return;

    let seriesTag = null;
    let cleanSeriesName = null;

    // 1. 태그 중 '시리즈:'로 시작하는 진짜 시리즈 태그 찾기
    labelLinks.forEach(link => {
        let text = link.textContent.trim();
        // 사이드바 위젯의 (글 개수) 텍스트 분리
        let pureText = text.split('(')[0].trim(); 

        if (pureText.startsWith('시리즈:')) {
            if (!seriesTag) {
                seriesTag = pureText; // 내부 검색용 (예: "시리즈: 자바스크립트")
                cleanSeriesName = pureText.replace('시리즈:', '').trim(); // UI 출력용 (예: "자바스크립트")
            }
            // 화면에 렌더링되는 모든 곳에서 '시리즈:' 글자를 감쪽같이 지움 (사용자 눈엔 안 보임)
            link.innerHTML = link.innerHTML.replace('시리즈:', '').trim();
        }
    });

    // 2. '시리즈:' 태그가 달리지 않은 일반 글(공지만 있는 글 등)이면 시리즈 UI 생성 없이 조용히 종료
    if (!seriesTag) return;

    const currentUrl = window.location.href.split(/[?#]/)[0];

    // 번호 추출 함수
    const extractNumber = (text) => {
        const match = text.match(/([0-9]+[-.][0-9]+(?:[-.][0-9]+)*)/);
        return match ? match[1] : null;
    };

    // 정렬 함수
    const compareNumbers = (a, b) => {
        const aParts = a.split(/[-.]/).map(Number);
        const bParts = b.split(/[-.]/).map(Number);
        for (let i = 0; i < Math.max(aParts.length, bParts.length); i++) {
            const v1 = aParts[i] || 0;
            const v2 = bParts[i] || 0;
            if (v1 !== v2) return v1 - v2;
        }
        return 0;
    };

    // 제목 깔끔하게 포맷팅하는 함수
    const formatTitle = (num, title) => {
        if (!num) return title;
        const cleanText = title.replace(num, '').replace(/^[\s\-.:_]+/, '').trim();
        return `${num} ${cleanText}`;
    };

    // 🚀 찾아낸 시리즈 태그(seriesTag)로 해당 태그가 달린 글만 정확히 긁어옴
    const feedUrl = `/feeds/posts/default/-/${encodeURIComponent(seriesTag)}?alt=json&max-results=100`;

    fetch(feedUrl)
        .then(res => res.json())
        .then(data => {
            const entries = data.feed.entry || [];
            let postList = entries.map(entry => {
                const title = entry.title.$t;
                const content = entry.content ? entry.content.$t : "";
                const link = entry.link.find(l => l.rel === 'alternate').href.split(/[?#]/)[0];

                let num = extractNumber(title);
                if (!num && content) {
                    const h1Match = content.match(/<h1[^>]*>(.*?)<\/h1>/i);
                    if (h1Match) num = extractNumber(h1Match[1]);
                }

                return { title, link, num };
            })
            .filter(p => p.num) // 번호 있는 글만 필터링
            .sort((a, b) => compareNumbers(a.num, b.num));

            const currentIndex = postList.findIndex(p => p.link === currentUrl);
            if (currentIndex === -1) return;

            const prevPost = postList[currentIndex - 1];
            const nextPost = postList[currentIndex + 1];

            // 3. 드롭다운 HTML 생성
            let listHtml = '<ul class="series-dropdown-list">';
            postList.forEach((p, idx) => {
                const isCurrent = (idx === currentIndex);
                const displayTitle = formatTitle(p.num, p.title);
                listHtml += `<li class="${isCurrent ? 'current' : ''}">
                                <a href="${p.link}">${displayTitle}</a>
                             </li>`;
            });
            listHtml += '</ul>';

            const prevTitle = prevPost ? formatTitle(prevPost.num, prevPost.title) : '';
            const nextTitle = nextPost ? formatTitle(nextPost.num, nextPost.title) : '';

            // 4. UI 래퍼 생성 (타이틀에 'cleanSeriesName' 적용)
            const navWrapper = document.createElement('div');
            navWrapper.id = 'modern-series-nav';
            navWrapper.innerHTML = `
                <div class="series-header" id="series-toggle-btn">
                    <div class="series-meta">
                        <span class="badge">SERIES</span>
                        <span class="series-title">'${cleanSeriesName}' 모아보기</span>
                    </div>
                    <div class="series-meta-right">
                        <span class="series-count">${currentIndex + 1} / ${postList.length}</span>
                        <span class="toggle-icon">▼</span>
                    </div>
                </div>
                <div class="series-dropdown" id="series-dropdown-content" style="display: none;">
                    ${listHtml}
                </div>
                <div class="series-nav-footer">
                    ${prevPost ? `
                        <a href="${prevPost.link}" class="nav-btn prev">
                            <span class="dir">← 이전 편</span>
                            <span class="tit">${prevTitle}</span>
                        </a>
                    ` : '<div class="nav-btn empty"></div>'}
                    ${nextPost ? `
                        <a href="${nextPost.link}" class="nav-btn next">
                            <span class="dir">다음 편 →</span>
                            <span class="tit">${nextTitle}</span>
                        </a>
                    ` : '<div class="nav-btn empty"></div>'}
                </div>
            `;

            const postBody = document.querySelector('.post-body');
            if (postBody) postBody.parentNode.insertBefore(navWrapper, postBody.nextSibling);

            // 드롭다운 토글 클릭 이벤트
            document.getElementById('series-toggle-btn').addEventListener('click', function() {
                const dropdown = document.getElementById('series-dropdown-content');
                const isHidden = dropdown.style.display === 'none';
                dropdown.style.display = isHidden ? 'block' : 'none';
                this.classList.toggle('open', isHidden);
            });
        });
});
//

//
// 🚀 [글로벌] 스켈레톤 마스터 컨트롤러

window.SkeletonMaster = {
  apply: function(container) {
    // 1. 이미지는 로딩이 완전히 끝날 때까지 뼈대 유지
    const images = container.querySelectorAll('img');
    images.forEach(img => {
      if (!img.complete) {
        img.classList.add('skeleton-ui');
        if (!img.getAttribute('height')) img.style.minHeight = '200px';
        img.addEventListener('load', () => {
          img.classList.remove('skeleton-ui');
          img.style.minHeight = '';
        });
        img.addEventListener('error', () => img.classList.remove('skeleton-ui'));
      }
    });

    // ✨ 타겟이 글 목록(더보기 카드)일 때만 자기 자신도 뼈대 처리 (본문 post-body 삭제됨)
    if (container.classList && (container.classList.contains('post-outer-container') || container.classList.contains('post'))) {
      container.classList.add('skeleton-ui');
    }
  },

  remove: function(container) {
    // 내부 자식들의 뼈대 벗기기
    const blocks = container.querySelectorAll('.skeleton-ui:not(img)');
    blocks.forEach(b => b.classList.remove('skeleton-ui'));

    // ✨ 자기 자신이 뼈대였으면 본인도 벗기기
    if (container.classList && container.classList.contains('skeleton-ui')) {
      container.classList.remove('skeleton-ui');
    }
  }
};


// 쉬머링 코드
document.addEventListener("DOMContentLoaded", function() {

// 🚀 2. [클릭 반응 - 글 카드] 메인 화면 글 카드 클릭 시 전체 포커스
  if (!document.body.classList.contains('item-view')) {
    document.body.addEventListener('click', function(e) {
      const card = e.target.closest('.post-outer-container, .PopularPosts .post');
      if (!card) return;

      // 💡 [이슈 방어] 태그, 날짜, 하단 버튼 등 개별 클릭이 필요한 요소를 눌렀을 때는 무시
      if (e.target.closest('.post-bottom, .post-labels, .byline')) return;

      // 💡 [이슈 방어] <a> 태그의 target="_blank" 이거나, Ctrl/Cmd/Shift/휠 클릭(새 창 열기)인 경우 작동 취소!
      if (e.target.tagName.toLowerCase() === 'a' && e.target.target === '_blank') return;
      if (e.ctrlKey || e.metaKey || e.shiftKey || e.button === 1) return;

      const mainLink = card.querySelector('.post-title a, .item-title a');
      if (!mainLink) return;

      // 원본은 놔두고 중복 클릭만 방지
      card.style.pointerEvents = 'none'; 

      // 나머지 카드들만 흐리게 처리
      document.querySelectorAll('.post-outer-container, .PopularPosts .post').forEach(other => {
        if (other !== card) {
          other.style.opacity = '0.4';
          other.style.pointerEvents = 'none';
        }
      });

      // 🚀 핵심 버그 픽스: <a> 태그를 정확히 누르지 않고 카드 여백을 눌렀더라도 강제로 페이지 이동!
      if (e.target.tagName.toLowerCase() !== 'a') {
        window.location.href = mainLink.href;
      }
    });
  }

  // 🚀 3. [클릭 반응 - 내부 링크] 사이드바 등 위젯 스켈레톤 변환
  const internalLinks = document.querySelectorAll('.sidebar-container a, .series-list a, .series-dropdown-list a, .nav-btn');
  internalLinks.forEach(link => {
    link.addEventListener('click', function(e) {
      // 💡 [이슈 방어] 새 창 열기 단축키 클릭 시 무시
      if (e.ctrlKey || e.metaKey || e.shiftKey || e.button === 1) return;

      const href = this.getAttribute('href');
      if (!href || href.startsWith('#') || this.target === '_blank') return;

      const parentWidget = this.closest('.widget, .series-box, #modern-series-nav');
      if (parentWidget) {
        parentWidget.classList.add('skeleton-ui');
        parentWidget.style.pointerEvents = 'none';
      }
    });
  });

  // 🚀 [추가] 뒤로가기(Bfcache) 버그 완벽 복구 로직
  window.addEventListener('pageshow', function(e) {
    // 브라우저 뒤로가기/앞으로가기로 페이지에 진입했거나 캐시된 페이지일 때
    if (e.persisted || (window.performance && window.performance.getEntriesByType("navigation")[0].type === 'back_forward')) {

      // 1. 글 카드 흐림 효과 및 클릭 방지 모두 해제 (초기화)
      document.querySelectorAll('.post-outer-container, .PopularPosts .post').forEach(card => {
        card.style.opacity = '';
        card.style.pointerEvents = '';
      });

      // 2. 사이드바 등 위젯에 씌워졌던 스켈레톤 상태 강제 제거
      document.querySelectorAll('.skeleton-ui').forEach(el => {
        el.classList.remove('skeleton-ui');
        el.style.pointerEvents = '';
      });
    }
  });
  // 🚀 4. [글 본문 화면] 본문 가짜 스켈레톤 박스 생성
  const postBodyNode = document.querySelector('.post-body');
  let skelWrapper = null;

  if (postBodyNode && document.body.classList.contains('item-view')) {
    skelWrapper = document.createElement('div');
    skelWrapper.className = 'post-skeleton-wrapper';
    skelWrapper.innerHTML = `
      <div class="skeleton-ui skel-title"></div>
      <div class="skeleton-ui skel-line"></div>
      <div class="skeleton-ui skel-line"></div>
      <div class="skeleton-ui skel-line"></div>
      <div class="skeleton-ui skel-line short"></div>
      <div class="skeleton-ui skel-box"></div>
      <div class="skeleton-ui skel-line"></div>
      <div class="skeleton-ui skel-line short"></div>
    `;
    postBodyNode.parentNode.insertBefore(skelWrapper, postBodyNode);
  }

  // 🚀 5. [수식 렌더링 완료 후 봉인 해제!]
  SkeletonMaster.apply(document); 

const initRender = async () => {
    // 1. 브라우저에게 메인 스레드 양보 (댓글창 통신 및 렌더링 우선권 부여)
    await new Promise(resolve => setTimeout(resolve, 50));

    // 2. 가벼운 DOM 조작인 콜아웃 파싱 먼저 실행
    if (window.initCallouts) window.initCallouts();

    // 3. 다시 한번 숨 고르기 (작업 사이에 틈을 주어 댓글창이 멈추지 않게 함)
    await new Promise(resolve => setTimeout(resolve, 50));

    // 4. 코드 블록 하이라이팅 실행
    if (window.initCodeBlocks) window.initCodeBlocks();

    // 5. 가장 무거운 작업인 MathJax 수식 렌더링을 '우선순위 최하단'으로 강등
    const renderMathAndFinish = async () => {
      if (window.MathJax && MathJax.typesetPromise) {
        try { await MathJax.typesetPromise(); } catch(e){}
      }

      // 6. 모든 무거운 작업이 끝난 후 최종적으로 스켈레톤(뼈대) 해제
      document.documentElement.classList.remove('is-rendering');
      document.body.classList.add('is-loaded'); 
      SkeletonMaster.remove(document); 

      if (skelWrapper) skelWrapper.remove(); 
      if (postBodyNode) postBodyNode.style.display = 'block'; 
    };

    // 브라우저가 여유로울 때(Idle) 수식 렌더링을 실행하도록 지시
    if ('requestIdleCallback' in window) {
      requestIdleCallback(renderMathAndFinish, { timeout: 2000 });
    } else {
      setTimeout(renderMathAndFinish, 200); // 지원하지 않는 브라우저를 위한 폴백
    }
  };

  initRender();


  // (이 아래부터는 기존에 있던 더보기 로직 등 나머지 코드가 이어지면 됩니다)
  if (document.body.classList.contains('item-view')) return;
  // ...


  // 아래부터는 기존 '더보기 + 복원' 로직
  if (document.body.classList.contains('item-view')) return;

  const blogWidget = document.querySelector('#Blog1');
  const blogPager1 = document.querySelector('.blog-pager');
  const blogPager2 = document.getElementById('blog-pager');
  const blogPager = blogPager1 ? blogPager1 : blogPager2;

  if (!blogWidget) return;
  if (blogPager) blogPager.style.display = 'none';

  const loadMoreWrapper = document.createElement('div');
  loadMoreWrapper.className = 'load-more-wrapper';
  loadMoreWrapper.innerHTML = '<button id="load-more-btn" class="load-more-btn">더보기 ↓</button>';
  blogWidget.parentNode.insertBefore(loadMoreWrapper, blogWidget.nextSibling);

  const loadMoreBtn = document.getElementById('load-more-btn');
  let nextPageUrl = '';

  const targetContainer1 = document.querySelector('#Blog1 .blog-posts');
  const targetContainer2 = document.querySelector('#Blog1 div[role="feed"]');
  const targetContainer3 = document.querySelector('#Blog1 .widget-content');
  const targetContainer = targetContainer1 ? targetContainer1 : (targetContainer2 ? targetContainer2 : targetContainer3);

  if (!targetContainer) return;

  // 🚀 [핵심 수정 부분] 현재 접속한 URL 경로를 가져와서 고유한 캐시 키를 만듭니다.
  const currentPath = window.location.pathname + window.location.search;
  const cacheHtmlKey = 'blogger_saved_posts_' + currentPath;
  const cacheUrlKey = 'blogger_saved_next_url_' + currentPath;
  const cacheScrollKey = 'blogger_saved_scroll_' + currentPath;

  if (window.performance) {
    const navEntries = window.performance.getEntriesByType("navigation");
    if (navEntries.length > 0) {
      if (navEntries[0].type === "reload") {
        // 고정된 문자열 대신 동적 키(Key) 사용
        sessionStorage.removeItem(cacheHtmlKey);
        sessionStorage.removeItem(cacheUrlKey);
        sessionStorage.removeItem(cacheScrollKey);
      }
    }
  }

  // 고정된 문자열 대신 동적 키(Key) 사용
  const savedHtml = sessionStorage.getItem(cacheHtmlKey);
  const savedNextUrl = sessionStorage.getItem(cacheUrlKey);

  if (savedHtml) {
    targetContainer.insertAdjacentHTML('beforeend', savedHtml);

    // ✨ 복원된 데이터에도 렌더링 후 스켈레톤 벗기기 적용
    const finalizeRestore = async () => {
      if (window.MathJax) {
        if (MathJax.typesetPromise) {
          try { await MathJax.typesetPromise(); } catch(e){}
        }
      }
      if (window.initCodeBlocks) window.initCodeBlocks();
      if (window.initCallouts) window.initCallouts();
      if (window.initImageZoom) window.initImageZoom();
      setTimeout(() => SkeletonMaster.remove(targetContainer), 300);
    };
    finalizeRestore();

    // 고정된 문자열 대신 동적 키(Key) 사용
    const savedScroll = sessionStorage.getItem(cacheScrollKey);
    if (savedScroll) {
      setTimeout(function() { window.scrollTo(0, parseInt(savedScroll, 10)); }, 150);
    }
  }

  if (savedNextUrl) {
    nextPageUrl = savedNextUrl;
    if (nextPageUrl !== 'null') {
      loadMoreBtn.innerHTML = '더보기 ↓';
      loadMoreBtn.disabled = false;
    } else {
      loadMoreWrapper.style.display = 'none';
    }
  } else {
    updateNextPageUrl(document);
  }

  function updateNextPageUrl(doc) {
    const olderLink1 = doc.querySelector('#Blog1 .blog-pager-older-link');
    const olderLink2 = doc.querySelector('.blog-pager-older-link');
    const olderLink = olderLink1 ? olderLink1 : olderLink2;

    if (olderLink) {
      nextPageUrl = olderLink.href.split('#')[0];
    } else {
      nextPageUrl = 'null';
    }

    if (nextPageUrl === 'null') {
      loadMoreWrapper.style.display = 'none';
    } else {
      loadMoreBtn.innerHTML = '더보기 ↓';
      loadMoreBtn.disabled = false;
    }
    // 고정된 문자열 대신 동적 키(Key) 사용
    sessionStorage.setItem(cacheUrlKey, nextPageUrl);
  }

  loadMoreBtn.addEventListener('click', async function() {
    if (nextPageUrl === 'null') return;
    if (!nextPageUrl) return;

    loadMoreBtn.innerHTML = '<div class="lm-spinner"></div> 불러오는 중...';
    loadMoreBtn.disabled = true;

    try {
      const response = await fetch(nextPageUrl);
      const html = await response.text();
      const parser = new DOMParser();
      const doc = parser.parseFromString(html, 'text/html');
      const fetchedWidget = doc.querySelector('#Blog1');

      if (fetchedWidget) {
        const newPosts = fetchedWidget.querySelectorAll('.post-outer-container, article.post, .date-outer');

        if (newPosts.length > 0) {
          let rawHtmlToSave = '';

          newPosts.forEach(post => {
            post.style.animation = 'none';
            SkeletonMaster.apply(post); // ✨ 삽입 전에 미리 뼈대부터 입혀두기
            targetContainer.appendChild(post);
            rawHtmlToSave = rawHtmlToSave + post.outerHTML; 
          });

          // 고정된 문자열 대신 동적 키(Key) 사용
          const prevSaved = sessionStorage.getItem(cacheHtmlKey) || '';
          try {
            // 1. 평소처럼 누적 저장을 시도합니다.
            sessionStorage.setItem(cacheHtmlKey, prevSaved + rawHtmlToSave);
          } catch (error) {
console.warn('⚠️ 캐시 용량(5MB) 초과: 전체 더보기 캐시를 안전하게 비웁니다.');
  // blogger_saved_ 로 시작하는 모든 찌꺼기 캐시를 일괄 삭제
  Object.keys(sessionStorage).forEach(key => {
    if (key.startsWith('blogger_saved_')) {
      sessionStorage.removeItem(key);
    }
  });
}
        // ✨ 렌더링 완료 후 뼈대 벗기기 (CPU 최적화 적용)
          const finalizeLoad = async () => {
            if (window.MathJax && MathJax.typesetPromise) {
              // 🚀 전체가 아닌 '새로 불러온 글(newPosts)'만 콕 집어서 수식 변환 (과부하 원천 차단)
              try { await MathJax.typesetPromise(Array.from(newPosts)); } catch(e){}
            }
            if (window.initCodeBlocks) window.initCodeBlocks();
            if (window.initCallouts) window.initCallouts();
            if (window.initImageZoom) window.initImageZoom();
            setTimeout(() => SkeletonMaster.remove(targetContainer), 300);
          };
          finalizeLoad();
        }
      }

      updateNextPageUrl(doc);

    } catch (error) {
      console.error("Load More Error:", error);
      loadMoreBtn.innerHTML = '불러오기 실패. 다시 시도';
      loadMoreBtn.disabled = false;
    }
  });

  window.addEventListener('beforeunload', function() {
    // 고정된 문자열 대신 동적 키(Key) 사용
    sessionStorage.setItem(cacheScrollKey, window.scrollY);
  });
});
