document.addEventListener("DOMContentLoaded", function() {


const settingsWrapper = document.createElement('div');
  settingsWrapper.innerHTML = `
    <div id="settings-panel">
      <div class="settings-header">블로그 설정 <button class="settings-close" id="st-close-btn">✕</button></div>
      <div class="settings-body">
        <div class="setting-item">
          <span style="white-space: nowrap; margin-right: 12px;">테마 모드</span>
          <div class="setting-group" id="theme-group" style="flex-grow: 1;">
            <button data-mode="light">라이트</button>
            <button data-mode="dark">다크</button>
            <button data-mode="auto">자동</button>
          </div>
        </div>
        <div class="setting-item">
          <span style="white-space: nowrap; margin-right: 12px;">폰트 스타일</span>
          <div class="setting-group" id="font-group" style="flex-grow: 1;">
            <button data-font="default">기본 (고딕)</button>
            <button data-font="latex">논문 (LaTeX)</button>
          </div>
        </div>
        <div class="setting-item" id="zen-option-item">
          <span>집중 모드 (Zen)</span>
          <button id="st-zen-btn">OFF</button>
        </div>
      </div>
    </div>
  `;


  document.body.appendChild(settingsWrapper);


// ⚙️ 2. 설정 버튼을 검색창에서 빼서 '플로팅 목차(ToC)' 안으로 쏙 이동!
  const fab = document.createElement('button');
  fab.id = "settings-fab";
  fab.className = "toc-btn"; // 목차 버튼과 동일한 클래스 부여하여 완벽 동기화
  fab.innerHTML = "<span class='gear-icon'>⚙</span>"; /* 🚨 이 부분만 껍데기를 씌워 수정! */
  fab.title = "화면 설정";

  const tocHeaderBtns = document.querySelector('.toc-header-btns');
  if (tocHeaderBtns) {
    tocHeaderBtns.prepend(fab); // 새로고침(↺) 버튼 바로 왼쪽에 추가
  } else {
    // 혹시 목차가 없는 짧은 글일 경우를 대비해 우측 하단 플로팅으로 띄움
    document.body.appendChild(fab);
    fab.style.cssText = "position:fixed; bottom:30px; right:30px; z-index:9999; font-size:24px; background:rgba(30,31,36,0.8); border:1px solid rgba(255,255,255,0.1); border-radius:50%; width:48px; height:48px; display:flex; justify-content:center; align-items:center; cursor:pointer;";
  }




  // 팝업 열기/닫기 로직
  const panel = document.getElementById('settings-panel');
  fab.onclick = () => panel.classList.toggle('open');
  document.getElementById('st-close-btn').onclick = () => panel.classList.remove('open');

  // --- 3. 테마 로직 (자동 모드 포함) ---
  const themeBtns = document.querySelectorAll('#theme-group button');
  const applyTheme = (mode) => {
    document.body.classList.remove('light-mode');
    themeBtns.forEach(b => b.classList.remove('active'));
    document.querySelector(`[data-mode="${mode}"]`).classList.add('active');

if (mode === 'light') document.body.classList.add('light-mode');
    else if (mode === 'dark') { /* 기본이 다크 */ }
    else if (mode === 'auto') {
      if (window.matchMedia('(prefers-color-scheme: light)').matches) document.body.classList.add('light-mode');
    }
    localStorage.setItem('blog-theme-mode', mode);

    // 테마가 바뀌면 이미지 팝업 배경색도 즉시 새로운 테마에 맞게 변경!
    if (window.initImageZoom) window.initImageZoom();
  };


themeBtns.forEach(btn => {
    btn.onclick = () => applyTheme(btn.dataset.mode);
  });
  applyTheme(localStorage.getItem('blog-theme-mode') || 'dark');



// --- 폰트 변경 로직 ---
  const fontBtns = document.querySelectorAll('#font-group button');
  const applyFont = (font) => {
    document.body.classList.remove('latex-font');
    fontBtns.forEach(b => b.classList.remove('active'));

    const activeBtn = document.querySelector(`#font-group [data-font="${font}"]`);
    if (activeBtn) activeBtn.classList.add('active');

    if (font === 'latex') document.body.classList.add('latex-font');
    localStorage.setItem('blog-font-style', font);
  };

  fontBtns.forEach(btn => {
    btn.onclick = () => applyFont(btn.dataset.font);
  });
  applyFont(localStorage.getItem('blog-font-style') || 'default');





  // --- 4. 집중 모드 (데스크탑 전용) ---
  const zenBtn = document.getElementById('st-zen-btn');
  if (window.innerWidth <= 800) document.getElementById('zen-option-item').style.display = 'none';
  zenBtn.onclick = () => {
    document.body.classList.toggle('zen-mode');
    zenBtn.textContent = document.body.classList.contains('zen-mode') ? "ON" : "OFF";
    zenBtn.classList.toggle('active');
    setTimeout(() => { if (typeof window.syncFolding === 'function') window.syncFolding(); }, 400);
  };
});











//

//
// 🚀 [통합] 스크롤 마스터 센서 (읽기 진행바 + 고스트 UI) - GPU 최적화
const progressBar = document.getElementById("reading-progress-bar"); // DOM 탐색 최소화 (밖으로 뺌)
let lastScrollTop = window.pageYOffset || document.documentElement.scrollTop;
const ghostThreshold = 80;
let ticking = false;

window.addEventListener('scroll', function() {
  if (!ticking) {
    window.requestAnimationFrame(function() {
      const currentScroll = window.pageYOffset || document.documentElement.scrollTop;
      const height = document.documentElement.scrollHeight - document.documentElement.clientHeight;

      // ① 상단 읽기 진행률 바 (GPU 가속)
      if (progressBar) progressBar.style.transform = "scaleX(" + (currentScroll / height) + ")";

      // ② 고스트 UI (메뉴 자동 숨김 & 모바일 바운스 방어)
      if (currentScroll >= 0 && currentScroll + window.innerHeight <= document.documentElement.scrollHeight) {
        if (currentScroll > lastScrollTop && currentScroll > ghostThreshold) {
          document.body.classList.add('ghost-ui-active');
        } else if (currentScroll < lastScrollTop) {
          document.body.classList.remove('ghost-ui-active');
        }
      }
      lastScrollTop = currentScroll;
      ticking = false;
    });
    ticking = true;
  }
}, { passive: true });
//

//
// [모바일 터치 호버 잔상 강제 초기화]
document.addEventListener('touchend', function() {
  setTimeout(function() {
    var activeEl = document.activeElement;
    if (activeEl && activeEl !== document.body) {
      var tag = activeEl.tagName.toLowerCase();
      if (tag !== 'input' && tag !== 'textarea' && !activeEl.isContentEditable) {
        activeEl.blur(); 
      }
    }
  }, 150);
}, { passive: true });
