document.addEventListener("DOMContentLoaded", function() {
  const modal = document.getElementById('spotlight-search-modal');
  const backdrop = document.getElementById('search-backdrop');
  const input = document.getElementById('spotlight-input');
  const resultsBox = document.getElementById('spotlight-results');
  const cancelBtn = document.getElementById('search-cancel-btn');

  let postCache = [];
  let isCacheLoaded = false;
  let isLoading = false;
  let selectedIndex = -1;
  let debounceTimer;
  let lastQuery = '';

  function fetchAllPosts(startIndex = 1) {
    isLoading = true;

    // 🚀 1. 신규 통신(startIndex=1)일 때만 5분 타이머 검사 및 초기화
    if (startIndex === 1) {
      const cachedPosts = sessionStorage.getItem('spotlight_cache');
      const cacheTimestamp = sessionStorage.getItem('spotlight_cache_time');
      const now = new Date().getTime();
      const CACHE_EXPIRE_MS = 5 * 60 * 1000; // 5분 유통기한

      // 캐시가 있고 5분이 안 지났다면 통신 생략
      if (cachedPosts && cacheTimestamp && (now - parseInt(cacheTimestamp) < CACHE_EXPIRE_MS)) {
        postCache = JSON.parse(cachedPosts);
        isLoading = false;
        isCacheLoaded = true;
        if (input.value.trim().length > 0) {
          lastQuery = ''; 
          input.dispatchEvent(new Event('input')); 
        } else {
          resultsBox.innerHTML = '<div class="search-hint">모든 글 인덱싱 완료! (캐시 적용)</div>';
        }
        return;
      } else {
        // 🚀 [버그 수정] 캐시가 만료되었으면 기존 배열(postCache)을 무조건 비워야 중복 복사 방지
        postCache = [];
        sessionStorage.removeItem('spotlight_cache');
        sessionStorage.removeItem('spotlight_cache_time');
      }
    }

    const fetchUrl = `/feeds/posts/default?alt=json&start-index=${startIndex}&max-results=150`;

    fetch(fetchUrl)
      .then(res => res.json())
      .then(data => {
        if (data.feed && data.feed.entry) {
          const entries = data.feed.entry.map(entry => {
            let rawContent = (entry.content && entry.content.$t) ? entry.content.$t : 
                             ((entry.summary && entry.summary.$t) ? entry.summary.$t : (entry.title.$t || ''));
            let pureText = rawContent.replace(/<[^>]*>?/gm, ''); 
            let alternateLink = entry.link ? entry.link.find(l => l.rel === 'alternate') : null;

            let tagsStr = entry.category ? entry.category.map(c => c.term).join('') : '';
            let combinedText = (entry.title.$t + tagsStr + pureText).toLowerCase().replace(/\s+/g, '');

            return {
              title: entry.title.$t,
              lowerTitle: entry.title.$t.toLowerCase().replace(/\s+/g, ''),
              tagsStr: tagsStr.toLowerCase(),
              link: alternateLink ? alternateLink.href : '#',
              tags: entry.category ? entry.category.map(c => c.term) : [],
              fullText: combinedText,
              displaySummary: pureText.substring(0, 100) + '...'
            };
          });

          postCache = postCache.concat(entries);
          const totalResults = parseInt(data.feed.openSearch$totalResults.$t);

          if (postCache.length < totalResults) {
            resultsBox.innerHTML = `<div class="search-hint">인덱싱 중... (${postCache.length} / ${totalResults})<br><small style="opacity:0.7">검색어를 미리 입력해두면 완료 즉시 결과를 보여줍니다.</small></div>`;
            fetchAllPosts(postCache.length + 1); 
          } else {
            // 🚀 파싱 완료 시 스토리지에 데이터 + 현재시간 동시 저장
    try {
  sessionStorage.setItem('spotlight_cache', JSON.stringify(postCache)); 
  sessionStorage.setItem('spotlight_cache_time', new Date().getTime().toString());
} catch (e) {
  console.warn('검색 데이터가 너무 커서 캐싱을 생략합니다.');
  // 에러가 나더라도 검색 기능 자체는 캐시 없이 정상 작동하게 됨
}
            isLoading = false;
            isCacheLoaded = true;

            if (input.value.trim().length > 0) {
              lastQuery = ''; 
              input.dispatchEvent(new Event('input')); 
            } else {
              resultsBox.innerHTML = '<div class="search-hint">모든 글 인덱싱 완료!</div>';
            }
          }
        } else {
          isLoading = false;
          isCacheLoaded = true;
        }
      })
      .catch(err => { isLoading = false; resultsBox.innerHTML = '<div class="search-hint">데이터를 불러오는 중 오류가 발생했습니다.</div>'; });
  }

  function openSearch(e) {
    if (e) { e.preventDefault(); e.stopImmediatePropagation(); }
    if (modal.classList.contains('active')) return;

    history.pushState({ isSearchModalOpen: true }, '');
    modal.classList.add('active');
    input.value = '';
    lastQuery = '';

    document.body.style.overflow = 'hidden';
    setTimeout(() => input.focus(), 100);

    // 🚀 2. [버그 수정] 검색창을 열 때 5분이 지났는지 재검사하여 자동 새로고침 진행
    const cacheTimestamp = sessionStorage.getItem('spotlight_cache_time');
    const now = new Date().getTime();
    const CACHE_EXPIRE_MS = 5 * 60 * 1000;

    if (!isCacheLoaded || (cacheTimestamp && (now - parseInt(cacheTimestamp) >= CACHE_EXPIRE_MS))) {
      isCacheLoaded = false;
      if (!isLoading) {
        resultsBox.innerHTML = '<div class="search-hint">인덱싱을 시작합니다...</div>';
        fetchAllPosts(1);
      }
    } else {
      resultsBox.innerHTML = '<div class="search-hint">검색어를 입력해 주세요.</div>';
    }
  }

  input.addEventListener('input', function() {
    let rawQuery = this.value.toLowerCase().trim();

    // 🚀 3. [버그 수정] 주인장 전용 초기화 명령어: 캐시 폭파 후 즉시 다시 인덱싱 시작
    if (rawQuery === '/초기화') {
      sessionStorage.removeItem('spotlight_cache');
      sessionStorage.removeItem('spotlight_cache_time');
      postCache = [];
      isCacheLoaded = false;
      this.value = '';
      lastQuery = '';
      resultsBox.innerHTML = '<div class="search-hint" style="color:#3182F6;">🔄 캐시 초기화 완료! 최신 글을 긁어옵니다...</div>';
      fetchAllPosts(1); // 즉시 긁어오기
      return;
    }

    if (!isCacheLoaded) {
      resultsBox.innerHTML = `<div class="search-hint">데이터를 로드 중입니다... (${postCache.length}개 로드됨)<br><small style="opacity:0.7">인덱싱이 끝나면 자동으로 검색됩니다.</small></div>`;
      return;
    }

    if (rawQuery === lastQuery) return;
    lastQuery = rawQuery;
    clearTimeout(debounceTimer);

    if (rawQuery.length === 0) {
      resultsBox.innerHTML = '<div class="search-hint">검색어를 입력해 주세요.</div>';
      return;
    }

    debounceTimer = setTimeout(() => {
      resultsBox.innerHTML = '';
      selectedIndex = -1;
      let searchTerms = rawQuery.split(/\s+/);
      let queryNoSpace = rawQuery.replace(/\s+/g, '');

      let matchedPosts = postCache.map(post => {
        let isMatch = searchTerms.every(term => post.fullText.includes(term.replace(/\s+/g, '')));
        if (!isMatch) return null;

        let score = 0;
        if (post.lowerTitle === queryNoSpace) score += 100;
        else if (searchTerms.every(term => post.lowerTitle.includes(term.replace(/\s+/g, '')))) score += 50;
        else if (searchTerms.every(term => post.tagsStr.includes(term.replace(/\s+/g, '')))) score += 30;
        else score += 10;

        return { ...post, score };
      }).filter(p => p !== null);

      matchedPosts.sort((a, b) => b.score - a.score);

      if (matchedPosts.length === 0) {
        resultsBox.innerHTML = '<div class="search-hint">검색 결과가 없습니다.</div>';
        return;
      }

      matchedPosts.slice(0, 15).forEach((post, index) => {
        let li = document.createElement('li');
        let tagsHtml = post.tags && post.tags.length > 0 
          ? `<div class="result-meta">${post.tags.map(t => `<span class="tag-pill">#${t}</span>`).join('')}</div>` 
          : '';

        li.innerHTML = `<a href="${post.link}" class="result-item" data-index="${index}">
          <span class="result-title">${post.title}</span>
          <span class="result-summary">${post.displaySummary}</span>
          ${tagsHtml}
        </a>`;
        resultsBox.appendChild(li);
      });
    }, 200);
  });

  function closeSearch(fromPopstate = false) {
    if (!modal.classList.contains('active')) return;
    modal.classList.remove('active');
    document.body.style.overflow = '';
    if (!fromPopstate && history.state && history.state.isSearchModalOpen) history.back();
  }
  window.addEventListener('popstate', (e) => { if (modal.classList.contains('active')) closeSearch(true); });
  backdrop.addEventListener('click', () => closeSearch(false));
  if (cancelBtn) cancelBtn.addEventListener('click', () => closeSearch(false));
  document.addEventListener('keydown', (e) => {
    if ((e.ctrlKey || e.metaKey) && e.key === 'k') { e.preventDefault(); openSearch(e); }
    if (e.key === 'Escape') closeSearch();
  });
  const searchButtons = document.querySelectorAll('.search-expand, .search-action, .search-button, .header-search, form[action*="/search"]');
  searchButtons.forEach(btn => btn.addEventListener('click', openSearch, true));

  input.addEventListener('keydown', function(e) {
    const items = resultsBox.querySelectorAll('.result-item');
    if (items.length === 0) return;
    if (e.key === 'Enter') {
      e.preventDefault();
      let targetIndex = selectedIndex >= 0 ? selectedIndex : 0;
      if (items[targetIndex]) items[targetIndex].click();
    } else if (e.key === 'ArrowDown') {
      e.preventDefault();
      selectedIndex = (selectedIndex + 1) % items.length;
      updateSelection(items);
    } else if (e.key === 'ArrowUp') {
      e.preventDefault();
      selectedIndex = (selectedIndex - 1 + items.length) % items.length;
      updateSelection(items);
    }
  });

  function updateSelection(items) {
    items.forEach(item => item.classList.remove('selected'));
    if (selectedIndex >= 0) {
      items[selectedIndex].classList.add('selected');
      items[selectedIndex].scrollIntoView({ block: "nearest" });
    }
  }
});






document.addEventListener("DOMContentLoaded", function() {
  const commentsContainer = document.getElementById('comments');
  if (!commentsContainer) return;

  const relocateButtons = () => {
    const realComments = document.querySelectorAll('.comment-thread > li.comment');

    realComments.forEach(comment => {
      const commentBlock = comment.querySelector('.comment-block');

      // 🚀 핵심: 자바스크립트도 껍데기 유령 버튼(.hidden)은 철저히 무시하고 진짜 버튼만 추적함
      const commentActions = comment.querySelector('.comment-actions:not(.hidden)');

      if (commentBlock && commentActions && commentActions.parentElement !== commentBlock) {
        commentBlock.appendChild(commentActions);
      }
    });
  };

  const observer = new MutationObserver(() => {
    relocateButtons();
  });

  observer.observe(commentsContainer, { childList: true, subtree: true });
});







