document.addEventListener("DOMContentLoaded", function() {
  const usedIds = new Set(); 

  // 1. 콜아웃 중복 ID 방지 및 해시태그 파싱
  document.querySelectorAll('.callout, .post-body blockquote').forEach((callout) => {
    const titleEl = callout.querySelector('.callout-title-inner') || callout.querySelector('.callout-title') || callout.querySelector('p');
    if (!titleEl || callout.id) return;

    let newId = '';
    const hashMatch = titleEl.textContent.match(/#([^\s]+)/); 

    if (hashMatch) {
      newId = hashMatch[1];
      titleEl.innerHTML = titleEl.innerHTML.replace(hashMatch[0], '').trim();
    } else {
      newId = titleEl.textContent.trim().replace(/\s+/g, '').substring(0, 20);
    }

    if (!newId) newId = 'callout-box';

    let finalId = newId;
    let counter = 1;
    while (usedIds.has(finalId)) {
      finalId = newId + '-' + counter;
      counter++;
    }

    callout.id = finalId;
    usedIds.add(finalId);
  });

  // 2. 참조 링크에 식별 클래스 추가 (새로운 위임 시스템용)
  const refLinks = document.querySelectorAll('.post-body a[href^="#"]:not([href*="#fn"])');
  refLinks.forEach(link => {
    link.classList.add('ref-link');
  });
}); // DOMContentLoaded 종료

/* =========================================
   레퍼런스(참조) 전용 팝업 시스템 (각주 코드와 분리!)
   ========================================= */
(function() {
    let activeTooltip = null;

function removeActiveTooltip() {
    // 팝업이 존재하고, 누군가에 의해 강제 삭제되지 않고 화면에 남아있을 때만
    if (activeTooltip && document.body.contains(activeTooltip)) {
        activeTooltip.style.opacity = '0';
        activeTooltip.style.transform = 'translateY(10px)';
        const target = activeTooltip;
        setTimeout(() => { if(target && target.parentNode) target.remove(); }, 200);
    }
    // 변수는 무조건 즉시 초기화하여 유령 방지
    activeTooltip = null; 
}

    document.addEventListener('click', function(e) {
        // 🚀 각주 링크를 클릭한 거라면 이 스크립트는 즉시 정지 (살려두신 각주 코드가 작동하도록 양보)
        if (e.target.closest('a[href*="#fn"]')) return;

        // 각주가 아닌, 레퍼런스 링크(.ref-link, #ref)만 감지
        const refLink = e.target.closest('.ref-link, a[href*="#ref"]');
      if (refLink) {
            e.preventDefault();
            e.stopPropagation();

            removeActiveTooltip();

            let refHash = refLink.hash ? refLink.hash : ('#' + refLink.getAttribute('href').split('#')[1]);
            const targetId = decodeURIComponent(refHash.substring(1));
            let targetEl = document.getElementById(targetId) || document.querySelector(`[name="${targetId}"]`);

            if (targetEl && targetEl.closest('.callout')) {
                targetEl = targetEl.closest('.callout');
            } else if (targetEl && targetEl.closest('blockquote')) {
                targetEl = targetEl.closest('blockquote');
            }

            if (!targetEl) return;

            const tooltip = document.createElement('div');
            tooltip.className = 'reference-tooltip';

            // 🚀 X버튼을 고정시키기 위한 '내부 스크롤 래퍼' 추가
            const innerScroll = document.createElement('div');
            innerScroll.className = 'ref-inner-scroll';

let contentHtml = targetEl.innerHTML;
            contentHtml = contentHtml.replace(/<a[^>]*class="[^"]*footnote-backref[^"]*"[^>]*>.*?<\/a>/gi, '');
            innerScroll.innerHTML = contentHtml; // 툴팁 본체가 아닌 래퍼 안에 내용을 넣음

            // 🚀 [추가] 팝업 내부의 접힌 콜아웃(Foldable Callout) 펼치기/접기 기능 부활
            const popupCallouts = innerScroll.querySelectorAll('.callout.is-collapsible');
            popupCallouts.forEach(callout => {
                const titleArea = callout.querySelector('.callout-title');
                if (titleArea) {
                    titleArea.style.cursor = 'pointer';
                    titleArea.addEventListener('click', function(ev) {
                        ev.preventDefault();
                        ev.stopPropagation(); // 클릭 시 팝업이 닫히거나 스크롤이 튀는 현상 방지
                        callout.classList.toggle('is-collapsed');
                    });
                }
            });

            // 🚀 X (닫기) 버튼 강제 주입

            // 🚀 X (닫기) 버튼 강제 주입
            const closeBtn = document.createElement('button');
            closeBtn.className = 'ref-close-btn'; // 위에서 정의한 CSS 클래스 연동
            closeBtn.innerHTML = '✕';
            closeBtn.onclick = function(ev) {
                ev.preventDefault();
                ev.stopPropagation();
                removeActiveTooltip();
            };

            // 버튼과 스크롤 래퍼를 각각 본체에 삽입
            tooltip.appendChild(closeBtn);
            tooltip.appendChild(innerScroll);

            document.body.appendChild(tooltip);
            activeTooltip = tooltip;

            // 위치 및 스크롤 계산 로직
            const rect = refLink.getBoundingClientRect();
            const tooltipHeight = tooltip.scrollHeight;
            const tooltipWidth = tooltip.offsetWidth;
            const spaceBelow = window.innerHeight - rect.bottom;
            const spaceAbove = rect.top;

            let topPos, startTransform, maxHeight;

            if (tooltipHeight + 20 > spaceBelow && spaceAbove > spaceBelow) {
                maxHeight = spaceAbove - 20;
                topPos = rect.top + window.scrollY - Math.min(tooltipHeight, maxHeight) - 10;
                startTransform = 'translateY(-10px)';
            } else {
                maxHeight = spaceBelow - 20;
                topPos = rect.bottom + window.scrollY + 10;
                startTransform = 'translateY(10px)';
            }

            if (window.innerWidth > 768) {
                let leftPos = rect.left + window.scrollX;
                if (leftPos + tooltipWidth > window.innerWidth - 15) {
                    leftPos = window.innerWidth - tooltipWidth - 15;
                }
                if (leftPos < 15) leftPos = 15;
                tooltip.style.left = leftPos + 'px';
            }

            tooltip.style.setProperty('top', topPos + 'px', 'important');
            tooltip.style.setProperty('bottom', 'auto', 'important');
            tooltip.style.setProperty('position', 'absolute', 'important');
            tooltip.style.setProperty('visibility', 'visible', 'important');
            tooltip.style.setProperty('opacity', '1', 'important');
            tooltip.style.transform = 'translateY(0)';

            // 🚀 스크롤 속성을 툴팁 본체가 아니라 '내부 래퍼'에 부여! (X버튼 고정)
            innerScroll.style.setProperty('max-height', maxHeight + 'px', 'important');

            if (window.MathJax && window.MathJax.typesetPromise) {
                window.MathJax.typesetPromise([tooltip]);
            }
        }
        else if (activeTooltip && !e.target.closest('.reference-tooltip')) {
            removeActiveTooltip();
        }
    });
})();




/* =========================================================
   [팝업 통합 제어] 참조 팝업과 각주 팝업 상호 배제 (동시 실행 방지)
========================================================= */
document.addEventListener('click', function(e) {
    // 1. 참조 링크를 클릭했는지 감지
    const clickedRef = e.target.closest('a.ref-link');

    // 2. 각주 링크를 클릭했는지 감지 (다양한 각주 태그 형태 모두 호환)
    const clickedFootnote = e.target.closest('a.footnote-ref, a.footnote-backref, sup a, a[href^="#fn"]');

    if (clickedRef) {
        // 🚀 참조 링크를 눌렀다면 -> 기존에 열려있는 '각주 팝업'을 부드럽게 지움
        document.querySelectorAll('.floating-footnote-content, .footnote-tooltip, [class*="footnote-content"]').forEach(el => {
            el.style.opacity = '0'; 
            setTimeout(() => el.remove(), 200); // 0.2초 페이드아웃 애니메이션 후 DOM에서 완전히 삭제
        });
    }

    if (clickedFootnote) {
        // 🚀 각주 링크를 눌렀다면 -> 기존에 열려있는 '참조 팝업'을 부드럽게 지움
        document.querySelectorAll('.reference-tooltip').forEach(el => {
            el.style.opacity = '0';
            setTimeout(() => el.remove(), 200);
        });
    }
}, true); // 이벤트 캡처링(true)을 켜서 기존 팝업 스크립트들이 작동하기 '직전'에 선빵을 날려 청소합니다!













